var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 머리가 울려…… 여긴 아카데미? ……가 아니라, 애쉬포드 학원인가?","JPN":"なんだか耳鳴りがする……ここは？\\nアカデミー……、じゃない。ここは、アッシュフォード学園。","ENG":"My head's ringing... Is this the Academy? ...No, wait. Ashford Academy?","TWN":"我的頭嗡嗡作響……這裡是學院？……不對，是阿什弗德學院？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으, 어쩐지 멀미하는 것처럼 기분이 안 좋아.","JPN":"うう、乗り物酔いしたみたいに気持ち悪い……","ENG":"Ugh, I feel so nauseous.","TWN":"呃，好像暈車的感覺，好暈。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아! 오늘은 분명 학원제가…….","JPN":"そうだ！　今日は学園祭のはず……","ENG":"Right! Today's the day of the festival...","TWN":"對了！今天是學園祭……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"어이, 거기 간판이 기울어졌어. 이대로는 내일 학원제까지 부스 설치가 끝나지 않는다고!","JPN":"おい、そこの看板が傾いてるぞ。\\nこんなんじゃ明日の学園祭までに屋台の設置が間に合わない！","ENG":"Hey, the sign's not level. At this rate, the booths won't be ready by tomorrow's festival!","TWN":"喂，招牌歪了，這樣攤位佈置會趕不上明天的學園祭！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"내일, 학원제가 시작 전까지 여기 다 치워놔~","JPN":"明日、学園祭が始まる前に、ここの片付けは済ませておけよー。","ENG":"Make sure to clean up here before the festival starts tomorrow!","TWN":"明天學園祭開始前要把這裡清乾淨。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 학원제는 분명 오늘이었을 텐데?","JPN":"あれ？　学園祭は今日のはずじゃなかったっけ？","ENG":"What? Isn't it supposed to be today?","TWN":"搞什麼？學園祭不是今天嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 아직도 학원제를 준비 하고 있잖아? 이건 대체…….","JPN":"でも、まだみんなは準備を進めている。これはいったい……","ENG":"But why are they still getting ready for it? What's going on...?","TWN":"怎麼還在準備學園祭？這是怎麼回事……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 곧 <color=#ffd34c>전야제</color>가 끝이 날 거야. 이번에는 시간이 별로 없어.","JPN":"しかし、まもなく今日が、<color=#ffd34c>学園祭の前日</color>が終わる。今回はもう時間がない。","ENG":"The <color=#ffd34c>festival preparation</color> is going to end soon. We don't have a lot of time right now.","TWN":"但<color=#ffd34c>這一天</color>就快結束了，這次沒剩多少時間了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 기억은…… 를르슈?","JPN":"この記憶は……ルルーシュ？","ENG":"This memory... Lelouch?","TWN":"這段記憶是…… 魯路修？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 내가 어제 를르슈랑 무슨 말을 했었지?","JPN":"待って。私は昨日、ルルーシュと何の話をしたんだっけ？","ENG":"Wait, what did I talk about with Lelouch yesterday?","TWN":"等等，我昨天和魯路修說了什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가를 기억해내라고 했던 것 같은데…….","JPN":"何かを思い出せと言われたような……","ENG":"I think he told me to remember something...","TWN":"他好像叫我要想起什麼……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 이제 시간이 별로 없어.","JPN":"ミナ、あまり時間がない。","ENG":"Mina, we're running out of time.","TWN":"米娜，沒時間了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이 학원제를 끝내 버리기 위해서는 너의 힘이 필요해.","JPN":"俺たちがこの<color=#ffd34c>学園祭の前日</color>から抜け出すためには、お前の力が必要なんだ。","ENG":"I need your help to end this festival.","TWN":"要結束這場學園祭，就需要你的力量。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학원제를 끝내 버린다고……?","JPN":"<color=#ffd34c>学園祭の前日</color>から抜け出すって……？","ENG":"End the festival...?","TWN":"結束學園祭……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"큿, 점점 더 모르겠어. 어제 대체 무슨 이야기를 한 거야?","JPN":"くっ、段々わからなくなってきた。昨日はいったい何の話をしたんだろう？","ENG":"Kgh, it's making less and less sense. What did I talk about with him yesterday?","TWN":"唔，越想越混亂，昨天到底說了什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"역시…… 본인한테 직접 물어보는 수밖에 없나?","JPN":"やっぱり……本人に直接聞くしかないかな？","ENG":"I guess... I'll just have to ask him directly.","TWN":"果然……還是只能去問本人嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단 학생회실로 가볼까?","JPN":"とりあえず生徒会室に行ってみよう。","ENG":"Let's head to the Student Council office first.","TWN":"先去學生會辦公室吧？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아직 전야제가 시작 전이라서 그런가? 아무도 없네?","JPN":"まだ学園祭の前だからかな？　誰もいないや。","ENG":"Is it because the festival preparation hasn't started yet? No one's here.","TWN":"幹部會議還沒開始嗎？怎麼都沒有人？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L34_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이 학원제를 끝내 버리기 위해서는 너의 힘이 필요해.","JPN":"俺たちがこの<color=#ffd34c>学園祭の前日</color>から抜け出すためには、お前の力が必要なんだ。","ENG":"I need your help to end this festival.","TWN":"要結束這場學園祭，就需要你的力量。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"반드시 기억해내는 거야, 유미나…….","JPN":"必ず思い出すんだ、ヤナギ・ミナ……","ENG":"You have to keep remembering, Yoo Mina...","TWN":"劉米娜，你一定要想起來……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"킹의 발 밑을…….","JPN":"キングの足下を……","ENG":"Under the king...","TWN":"國王的腳底……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"킹의…… 발 밑? 뭔가 비유적인 뜻인가?","JPN":"キングの……足下？　何かの比喩かな？","ENG":"Under... the king? Is that supposed to mean anything?","TWN":"國王的……腳底？這是在比喻什麼嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내 발 밑에는 아무것도…….","JPN":"私の足元には何も……","ENG":"There's nothing below mine...","TWN":"我的腳底什麼也沒……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라? 그러고보니 이 체스판 전에 봤을 때랑 묘하게 배치가 달라졌어.","JPN":"あれ？\\nそういえばこのチェスボード、前に見た時と微妙に配置が変わってる。","ENG":"Huh? Looks like the chess pieces on the board have been slightly changed.","TWN":"喔？這麼說來，這個棋盤上的棋子，似乎擺得和之前不太一樣。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"엇!? 혹시, 킹이라는 게 이 체스말의 킹을 말하는 거야?","JPN":"あっ！？　もしかして、キングってこのチェスの駒のキングのこと？","ENG":"Huh?! Wait, by \\"king,\\" did he mean this chess piece?!","TWN":"喔！？難道國王是指西洋棋的國王嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말인가 봐. 진짜 체스 말 바닥에 쪽지가 붙어있어.","JPN":"あっていたみたいね。チェスの駒の底にメモがある。","ENG":"It must be. There's a note stuck on the bottom of the king.","TWN":"好像是！棋子的底下有黏著紙條。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"숨겨 놓았다는 건. 다른 누군가에게는 들키고 싶지 않다는 뜻.","JPN":"隠してある、ということは、ほかの誰かには知られたくないということ。","ENG":"He hid it, which means he doesn't want others to find out about it.","TWN":"會藏起來，就表示不想被其他人發現。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이렇게까지 해서 를르슈는 나에게 뭘 전하려는 거지……?","JPN":"そこまでして、ルルーシュは私に何を伝えようと……？","ENG":"Why did he go through all this trouble just to tell me something...?","TWN":"會做到這種程度，魯路修到底是想和我說什麼……？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"한 번에 질문이 너무 많군. 미안하지만 전부 대답하기에는 시간이 없어.","JPN":"一度に質問が多すぎるな。悪いが、全て答えるには時間がない。","ENG":"You're asking too many questions at once. I'm sorry, but I have no time to answer them all.","TWN":"你一下子問這麼多問題，很抱歉，我沒時間全部回答你。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이전 루프에서 확인해본 결과, 여기서 너와 단 둘이 접촉할 수 있는 시간은 3분 정도니까.","JPN":"前のループで確かめた結果、お前と二人きりで接触できる時間はたったの3分程度だ。","ENG":"From the previous loop, I've confirmed that we have only 3 minutes to talk to each other in private.","TWN":"按照之前的經驗，我可以和你單獨相處的時間只有三分鐘左右。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이전 루프? 설마 이 기억은……!?","JPN":"前のループ？　もしかして、この記憶は……！？","ENG":"Previous loop? Could this memory be...?!","TWN":"之前的慣例？難道這段記憶是……！？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"우선, 실행위원장으로서 내일 학원제의 준비 상황을 보고하자면……","JPN":"さて、まずは学園祭実行委員長の俺から明日に控えた学園祭の進捗状況を報告する。","ENG":"First and foremost, as the head of the executive committee, I'll report on the status of preparations for tomorrow's festival...","TWN":"首先，就由身為執行委員長的我，來跟大家報告學園祭的準備情形……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L7_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전체적으로는 순조로운 편이지만, 현재 몇몇 동아리로부터 클레임이 접수된 상태야.","JPN":"全体的には順調だが、いくつか苦情やトラブルの報告が寄せられている。","ENG":"Everything is going smoothly overall, but a few clubs have filed some complaints.","TWN":"整體而言是順利的，只是有幾個社團提出一些訴求。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 임원들이 각각 분담해서 해결하면 좋겠네요.","JPN":"なるほど。役員で各トラブルを分担して解決を図りましょうか。","ENG":"I see. The members can each take charge of one and resolve the issues.","TWN":"是嗎？那就由幹部們一起分頭處理吧。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단, 상황을 정리해보자.","JPN":"とりあえず、状況を整理してみよう。","ENG":"Okay, let's try to make sense of this.","TWN":"我先重新整理一下。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"메모에 적힌 대로, 나는 지금까지 몇번이나 전야제를 반복하고 있었던 것 같아.","JPN":"メモに書かれていたたとおり、\\n私はこれまで何度も<color=#ffd34c>学園祭の前日</color>を繰り返してきたみたい。","ENG":"According to what was written on the letter, I've already repeated this day several times.","TWN":"根據紙條的內容，我似乎已經重複度過今天好幾次。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 나 말고 전야제의 루프를 눈치채고 있는 사람은 부회장 를르슈 한 명 뿐이야.","JPN":"そして私の他に、\\n<color=#ffd34c>学園祭の前日</color>のループに気づいているのは、副会長のルルーシュただ一人だけ。","ENG":"And only he and I have noticed that we're trapped in a loop.","TWN":"然而除了我之外，有發現到這件事的人，就只有副會長魯路修。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"를르슈는 이 학원제를 끝내 버리기 위해서는 내 도움이 필요하다고 했어.","JPN":"ルルーシュは終わりのない<color=#ffd34c>学園祭の前日</color>から抜け出すためには\\n私の力が必要と言ってた。","ENG":"Lelouch said that he needed my help to end this festival.","TWN":"魯路修說要結束這場學園祭，就需要我的幫助。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 몰래 <color=#ffd34c>이런 지시</color>를…….","JPN":"だからこっそり<color=#ffd34c>こんな指示</color>を……","ENG":"So that's why he secretly left <color=#ffd34c>these instructions</color>...","TWN":"所以才會偷偷將<color=#ffd34c>這張紙條</color>……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 정말로 를르슈를 믿을 수 있을까?","JPN":"でも、本当にルルーシュを信じてもいいのかな？","ENG":"But can I really trust Lelouch?","TWN":"不過，魯路修真的可信嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"반대로 녀석이 이 사태의 원흉이 아니라는 보장은 없는 거잖아?","JPN":"むしろ彼がこの事態の元凶かもしれない。","ENG":"I mean, there's no guarantee that he's not the cause of all this, right?","TWN":"反過來說，又沒證據證明他一定不是這件事的始作俑者？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"만약, 를르슈가 나를 속이려는 거라면……. 녀석에게 득이 되는 건 뭐지?","JPN":"もし、ルルーシュが私を騙そうとしているなら……\\nルルーシュの目的は何だろう？","ENG":"But even if he's trying to trick me... What does he gain from doing so?","TWN":"魯路修騙我的話……他可以得到什麼好處呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양? 아까부터 말씀이 없으시네요. 괜찮으세요?","JPN":"ミナさん？　さっきから静かですね、大丈夫ですか？","ENG":"Mina? You haven't said a word. Are you okay?","TWN":"米娜？你怎麼都不說話？還好嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 미안. 나도 잠깐 다른 걸 생각하고 있었어.","JPN":"あ、ごめん。ちょっと違うことを考えてた。","ENG":"Oh, sorry. I guess I zoned out again.","TWN":"喔，抱歉，我剛在想別的事。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……아니, 회장.","JPN":"……あの、会長。","ENG":"...Yen, wait.","TWN":"……那個，會長。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 나는 오늘 학원제 준비를 돕지 못할 것 같아.","JPN":"悪いけど、私は今日、学園祭の準備を手伝えそうにない。","ENG":"I don't think I can help with the festival preparations today.","TWN":"我今天可能無法幫忙預備學園祭。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왠지 컨디션이 별로 안 좋은 것 같거든. 미안하지만 조금 쉬어도 괜찮을까?","JPN":"なんだか具合が悪くて。悪いけど、少し休んでもいい？","ENG":"Can I rest for a bit? I don't feel so good.","TWN":"不好意思，我的狀況不太好，可以休息一下嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 어쩐지 낯빛이 좋지 않아 보였습니다.","JPN":"そうですか。なんとなく顔色がよくないと思っていました。","ENG":"I see. You do look a little pale.","TWN":"這樣嗎？難怪你看起來臉色不太好。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"몸이 안 좋다면 어쩔 수 없지.","JPN":"体調不良なら仕方ないよ。","ENG":"We can't make you work if you don't feel well.","TWN":"身體不舒服的話也只好這樣。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"그래, 미나. 학생회 일은 우리한테 맡기고 푹 쉬어.","JPN":"うん、ミナ。生徒会のことは私たちに任せてゆっくり休んでね。","ENG":"Yeah, Mina. Leave it to us and get some rest.","TWN":"是啊，米娜，學生會的事就交給我們，你好好休息。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……를르슈, 정말 학원제 준비를 돕지 않아도 괜찮을까?","JPN":"……ルルーシュ、\\n本当に私が学園祭の準備をを手伝わなくても大丈夫そう？","ENG":"...Lelouch, are you sure you don't need me to help out?","TWN":"……魯路修，我真的可以不幫忙準備學園祭嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"유미나, 너는 필요 이상으로 성실하군.","JPN":"ミナ、お前は必要以上に真面目だ。","ENG":"Yoo Mina, you really are diligent to a fault.","TWN":"劉米娜，你怎麼這麼老實。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"걱정하지 마, 한 명 정도라면 학원제 준비에는 지장이 없을 테니까.","JPN":"心配するな、一人ぐらいなら学園祭の準備に支障はないだろうさ。","ENG":"Don't worry. It's not like we can't get things done with one less person.","TWN":"放心吧，少一個人對於預備學園祭不會有問題的。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};